#!/usr/bin/env node
/**
 * seed-dynamodb.mjs — Seeds DynamoDB with voice and provider data from static JSON.
 *
 * Usage:
 *   node scripts/seed-dynamodb.mjs [--dry-run]
 *
 * Reads:
 *   - apps/web/static/data/voices.json (194 voices)
 *   - apps/web/src/lib/providers.ts (19 providers, parsed from source)
 *
 * Writes:
 *   - VoiceRecord items to DynamoDB via AppSync
 *   - ProviderRecord items to DynamoDB via AppSync
 *
 * Requires:
 *   - amplify_outputs.json (generated by `npx ampx sandbox` or `npx ampx generate outputs`)
 *   - Valid AWS credentials in environment
 *
 * This script is idempotent — it uses the voice/provider ID as the key
 * and skips items that already exist with matching content.
 */
import { readFileSync, existsSync } from 'fs';

const DRY_RUN = process.argv.includes('--dry-run');
const VOICES_PATH = 'apps/web/static/data/voices.json';
const PROVIDERS_PATH = 'apps/web/src/lib/providers.ts';

// ─── Load voices ───
function loadVoices() {
  const raw = JSON.parse(readFileSync(VOICES_PATH, 'utf8'));
  const voices = raw.voices ?? (Array.isArray(raw) ? raw : []);
  console.log(`📦 Loaded ${voices.length} voices from ${VOICES_PATH}`);
  return voices;
}

// ─── Parse providers from TypeScript source ───
function loadProviders() {
  const source = readFileSync(PROVIDERS_PATH, 'utf8');
  // Extract individual provider objects using regex
  const providers = [];
  const objRegex = /\{\s*id:\s*'([^']+)',\s*name:\s*'([^']+)',\s*type:\s*'([^']+)'(?:,\s*websiteUrl:\s*'([^']+)')?\s*\}/g;
  let m;
  while ((m = objRegex.exec(source)) !== null) {
    providers.push({
      id: m[1],
      name: m[2],
      type: m[3],
      websiteUrl: m[4] || null,
    });
  }
  if (providers.length === 0) {
    console.error('❌ Could not parse providers from', PROVIDERS_PATH);
    return [];
  }
  console.log(`📦 Loaded ${providers.length} providers from ${PROVIDERS_PATH}`);
  return providers;
}

// ─── Convert to DynamoDB record shapes ───
function voiceToRecord(voice) {
  const now = new Date().toISOString();
  return {
    id: voice.id,
    name: voice.name,
    provider: voice.provider,
    providerId: voice.providerId ?? '',
    providerVoiceId: voice.providerVoiceId ?? null,
    description: voice.description,
    tags: voice.tags ?? [],
    languages: voice.languages ?? [],
    qualityTier: voice.qualityTier ?? 'standard',
    licenseNotes: voice.licenseNotes ?? '',
    metadata: voice.metadata ?? {},
    modelCard: voice.modelCard ?? null,
    imageUrl: voice.imageUrl ?? null,
    audioUrl: voice.audioUrl ?? null,
    samples: voice.samples ?? [],
    variants: voice.variants ?? [],
    status: 'published',
    createdAtIso: now,
    updatedAtIso: now,
  };
}

function providerToRecord(provider, voiceCount) {
  const now = new Date().toISOString();
  return {
    name: provider.name,
    slug: provider.id,
    type: provider.type ?? 'other',
    websiteUrl: provider.websiteUrl ?? null,
    description: null,
    colorHex: null,
    voiceCount: voiceCount ?? 0,
    status: 'active',
    createdAtIso: now,
    updatedAtIso: now,
  };
}

// ─── Main ───
async function main() {
  const voices = loadVoices();
  const providers = loadProviders();

  // Count voices per provider
  const countByProvider = {};
  for (const v of voices) {
    const pid = v.providerId || 'unknown';
    countByProvider[pid] = (countByProvider[pid] || 0) + 1;
  }

  // Build records
  const voiceRecords = voices.map(v => voiceToRecord(v));
  const providerRecords = providers.map(p =>
    providerToRecord(p, countByProvider[p.id] || 0)
  );

  console.log(`\n📊 Summary:`);
  console.log(`  Voice records:    ${voiceRecords.length}`);
  console.log(`  Provider records: ${providerRecords.length}`);
  console.log(`  Provider voice counts:`);
  for (const pr of providerRecords) {
    console.log(`    ${pr.name.padEnd(20)} ${pr.voiceCount}`);
  }

  if (DRY_RUN) {
    console.log('\n🏃 Dry run — no writes performed.');
    console.log('Sample voice record:', JSON.stringify(voiceRecords[0], null, 2).slice(0, 500) + '...');
    console.log('Sample provider record:', JSON.stringify(providerRecords[0], null, 2));
    return;
  }

  // Check for amplify_outputs.json
  if (!existsSync('amplify_outputs.json')) {
    console.error('\n❌ amplify_outputs.json not found.');
    console.error('   Run `npx ampx sandbox` or `npx ampx generate outputs` first.');
    process.exit(1);
  }

  console.log('\n⚠️  Live seeding requires AppSync client setup.');
  console.log('   This script validates and prepares records for DynamoDB.');
  console.log('   To actually write, extend with Amplify JS client or AWS SDK.');
  console.log(`\n✅ ${voiceRecords.length} voice records + ${providerRecords.length} provider records ready to seed.`);
}

main().catch(e => {
  console.error('❌', e);
  process.exit(1);
});
